func TestSearchableText(t *testing.T) {
	input := `{
		"id": 12345,
		"payment": false,
		"cost": "42.50",
		"currency_code": "USD",
		"date": "2026-05-01",
		"description": "Taxi hotel transfer",
		"users": [{"first_name": "Alice"}],
		"receipt": "https://example.com/receipt",
		"contact_email": "alice@example.com"
	}`

	got := searchableText(input)
	for _, forbidden := range []string{"payment", "cost", "description", "usd", "2026-05-01", "12345"} {
		if strings.Contains(got, forbidden) {
			t.Fatalf("searchableText() unexpectedly contains %q in %q", forbidden, got)
		}
	}
	for _, required := range []string{"taxi", "hotel", "transfer", "alice"} {
		if !strings.Contains(got, required) {
			t.Fatalf("searchableText() missing %q in %q", required, got)
		}
	}
}

func TestSearchExactRelevance(t *testing.T) {
	dbPath := filepath.Join(t.TempDir(), "data.db")
	s, err := Open(dbPath)
	if err != nil {
		t.Fatalf("open: %v", err)
	}
	defer s.Close()

	items := []json.RawMessage{
		json.RawMessage(`{"id":"e1","description":"Taxi ride downtown","currency_code":"USD","payment":false,"cost":"12.00"}`),
		json.RawMessage(`{"id":"e2","description":"Hotel breakfast","currency_code":"USD","payment":false,"cost":"21.00"}`),
	}
	if _, _, err := s.UpsertBatch("expenses", items); err != nil {
		t.Fatalf("UpsertBatch: %v", err)
	}

	got, err := s.Search("payment", "", 50, false)
	if err != nil {
		t.Fatalf("Search(payment): %v", err)
	}
	if len(got) != 0 {
		t.Fatalf("Search(payment) returned %d results, want 0", len(got))
	}

	got, err = s.Search("USD", "", 50, false)
	if err != nil {
		t.Fatalf("Search(USD): %v", err)
	}
	if len(got) != 0 {
		t.Fatalf("Search(USD) returned %d results, want 0", len(got))
	}

	got, err = s.Search("taxi", "", 50, false)
	if err != nil {
		t.Fatalf("Search(taxi): %v", err)
	}
	if len(got) != 1 {
		t.Fatalf("Search(taxi) returned %d results, want 1", len(got))
	}
}

